package org.apache.commons.dbcp2.managed;

protected static class LocalXAResource implements XAResource { private final Connection connection ; private Xid currentXid ; private boolean originalAutoCommit ; public LocalXAResource ( final Connection localTransaction ) { this . connection = localTransaction ; } public synchronized Xid getXid ( ) { return currentXid ; } @ Override public synchronized void start ( final Xid xid , final int flag ) throws XAException { if ( flag == XAResource . TMNOFLAGS ) { if ( this . currentXid != null ) { throw new XAException ( "Already enlisted in another transaction with xid " + xid ) ; } try { originalAutoCommit = connection . getAutoCommit ( ) ; } catch ( final SQLException ignored ) { originalAutoCommit = true ; } try { connection . setAutoCommit ( false ) ; } catch ( final SQLException e ) { throw ( XAException ) new XAException ( "Count not turn off auto commit for a XA transaction" ) . initCause ( e ) ; } this . currentXid = xid ; } else if ( flag == XAResource . TMRESUME ) { if ( ! xid . equals ( this . currentXid ) ) { throw new XAException ( "Attempting to resume in different transaction: expected " + this . currentXid + ", but was " + xid ) ; } } else { throw new XAException ( "Unknown start flag " + flag ) ; } } @ Override public synchronized void end ( final Xid xid , final int flag ) throws XAException { Objects . requireNonNull ( xid , "xid is null" ) ; if ( ! this . currentXid . equals ( xid ) ) { throw new XAException ( "Invalid Xid: expected " + this . currentXid + ", but was " + xid ) ; } } @ Override public synchronized int prepare ( final Xid xid ) { try { if ( connection . isReadOnly ( ) ) { connection . setAutoCommit ( originalAutoCommit ) ; return XAResource . XA_RDONLY ; } } catch ( final SQLException ignored ) { } return XAResource . XA_OK ; } @ Override public synchronized void commit ( final Xid xid , final boolean flag ) throws XAException { Objects . requireNonNull ( xid , "xid is null" ) ; if ( this . currentXid == null ) { throw new XAException ( "There is no current transaction" ) ; } if ( ! this . currentXid . equals ( xid ) ) { throw new XAException ( "Invalid Xid: expected " + this . currentXid + ", but was " + xid ) ; } try { if ( connection . isClosed ( ) ) { throw new XAException ( "Connection is closed" ) ; } if ( ! connection . isReadOnly ( ) ) { connection . commit ( ) ; } } catch ( final SQLException e ) { throw ( XAException ) new XAException ( ) . initCause ( e ) ; } finally { try { connection . setAutoCommit ( originalAutoCommit ) ; } catch ( final SQLException e ) { } this . currentXid = null ; } } @ Override public synchronized void rollback ( final Xid xid ) throws XAException { Objects . requireNonNull ( xid , "xid is null" ) ; if ( ! this . currentXid . equals ( xid ) ) { throw new XAException ( "Invalid Xid: expected " + this . currentXid + ", but was " + xid ) ; } try { connection . rollback ( ) ; } catch ( final SQLException e ) { throw ( XAException ) new XAException ( ) . initCause ( e ) ; } finally { try { connection . setAutoCommit ( originalAutoCommit ) ; } catch ( final SQLException e ) { } this . currentXid = null ; } } @ Override public boolean isSameRM ( final XAResource xaResource ) { return this == xaResource ; } @ Override public synchronized void forget ( final Xid xid ) { if ( xid != null && xid . equals ( currentXid ) ) { currentXid = null ; } } @ Override public Xid [ ] recover ( final int flag ) { return new Xid [ 0 ] ; } @ Override public int getTransactionTimeout ( ) { return 0 ; } @ Override public boolean setTransactionTimeout ( final int transactionTimeout ) { return false ; } }